fun solve(nums: Array<Long>): Long {
    val n = nums.size
    var count = 0L
    for (i in 0 until n) {
        for (j in i + 1 until n) {
            val a = nums[i]
            val b = nums[j]
            val minVal = minOf(abs(a - b), abs(a + b))
            val maxVal = maxOf(abs(a - b), abs(a + b))
            val minAbs = minOf(abs(a), abs(b))
            val maxAbs = maxOf(abs(a), abs(b))
            if (minVal <= minAbs && maxVal >= maxAbs) {
                count++
            }
        }
    }
    return count
}
